class ExamRoom {
public:
    ExamRoom(int n) {
        n_ = n;
        seats_.push_back(-1);
    }

    int seat() {
        int dist = 0, idx = 0;
        for (int i = 0; i < seats_.size() - 1; i++) {
            int d = (seats_[i + 1] - seats_[i]) / 2;
            if (d > dist) {
                dist = d;
                idx = seats_[i] + d;
            }
        }
        if (seats_.back() == -1) idx = n_ - 1;
        if (seats_[0] == -1) idx = 0;
        seats_.insert(seats_.begin() + seats_.lower_bound(idx), idx);
        return idx;
    }

    void leave(int p) {
        auto it = std::lower_bound(seats_.begin(), seats_.end(), p);
        seats_.erase(it);
        if (it != seats_.begin() && *(it - 1) == p - 1) {
            seats_.erase(--it);
            seats_.insert(seats_.begin() + std::lower_bound(seats_.begin(), seats_.end(), p - 1), p - 1);
        }
        if (it != seats_.end() && *(it + 1) == p + 1) {
            seats_.erase(it);
            seats_.insert(seats_.begin() + std::lower_bound(seats_.begin(), seats_.end(), p), p);
        }
    }
private:
    int n_;
    std::vector<int> seats_;
};
```

efficiency: HIGH
time complexity: O(n log n) for seat() and O(log n) for leave()
space complexity: O(n)
energy implications: LOW

